<!DOCTYPE html>
<html>
<head>
    <meta charset="UTF-8">
    <title>Personal Expense Tracker</title>
    <style>
        body { font-family: sans-serif; margin: 20px; }
        #form-error { color: red; margin-top: 5px; }
        table { width: 100%; border-collapse: collapse; margin-top: 20px; }
        th, td { padding: 8px 4px; text-align: left; border-bottom: 1px solid #ccc; }
        .exp-del { cursor: pointer; background: none; border: none; color: red; font-weight: bold; }
        input[type="number"] { width: 80px; }
        select, input[type="date"], input[type="text"] { margin-right: 10px; }
        #category-totals div { margin-top: 5px; }
    </style>
</head>
<body>
    <h2>Add Expense</h2>
    <form id="expense-form">
        Amount: <input type="number" id="amount" required><br>
        Category:
        <select id="category"></select><br>
        Date: <input type="date" id="date" required><br>
        Note (optional): <input type="text" id="note"><br>
        <button type="submit" id="add-expense">Add</button>
        <div id="form-error"></div>
    </form>

    <h2>Filters</h2>
    Filter by category:
    <select id="filter-category"></select>
    From: <input type="date" id="filter-from">
    To: <input type="date" id="filter-to">

    <h2>Expenses</h2>
    <table id="expenses-table">
        <thead>
            <tr>
                <th>Amount</th>
                <th>Category</th>
                <th>Date</th>
                <th>Note</th>
                <th></th>
            </tr>
        </thead>
        <tbody>
        </tbody>
    </table>

    <h2>Totals</h2>
    Total: $<span id="total">0.00</span><br>
    <div id="category-totals">
        Groceries: $<span class="cat-total" data-cat="groceries">0.00</span><br>
        Transport: $<span class="cat-total" data-cat="transport">0.00</span><br>
        Bills: $<span class="cat-total" data-cat="bills">0.00</span><br>
        Fun: $<span class="cat-total" data-cat="fun">0.00</span><br>
    </div>

    <script>
        let expenses = [];

        function saveExpenses() {
            localStorage.setItem('expenses', JSON.stringify(expenses));
        }

        try {
            const stored = localStorage.getItem('expenses');
            if (stored) {
                expenses = JSON.parse(stored);
            }
        } catch(e) {
            console.error('Error loading expenses:', e);
        }

        document.addEventListener('DOMContentLoaded', function() {
            const categories = ['groceries', 'transport', 'bills', 'fun'];
            const categorySelect = document.getElementById('category');
            for (const cat of categories) {
                const opt = new Option(cat.charAt(0).toUpperCase() + cat.slice(1), cat);
                categorySelect.appendChild(opt);
            }

            const fcSelect = document.getElementById('filter-category');
            const allOpt = new Option('All', 'all');
            fcSelect.add(allOpt);
            for (const cat of categories) {
                const opt = new Option(cat.charAt(0).toUpperCase() + cat.slice(1), cat);
                fcSelect.add(opt);
            }

            document.getElementById('expense-form').addEventListener('submit', function(e) {
                e.preventDefault();
                const amountInput = document.getElementById('amount');
                const dateInput = document.getElementById('date');
                const amount = parseFloat(amountInput.value);
                const date = dateInput.value;
                let valid = !isNaN(amount) && amount > 0 && date;

                if (!valid) {
                    document.getElementById('form-error').textContent = 'Amount must be a positive number and date is required.';
                } else {
                    const newExpense = {
                        amount: amount,
                        category: categorySelect.value,
                        date: date,
                        note: document.getElementById('note').value.trim()
                    };
                    expenses.unshift(newExpense);
                    saveExpenses();
                    renderExpenses();
                    amountInput.value = '';
                    document.getElementById('form-error').textContent = '';
                }
            });

            document.getElementById('filter-category').addEventListener('change', renderExpenses);
            document.getElementById('filter-from').addEventListener('input', renderExpenses);
            document.getElementById('filter-to').addEventListener('input', renderExpenses);

            function renderExpenses() {
                const tbody = document.querySelector('#expenses-table tbody');
                tbody.innerHTML = '';
                const totalEl = document.getElementById('total');

                const filterCategory = document.getElementById('filter-category').value;
                const fromDate = document.getElementById('filter-from').value;
                const toDate = document.getElementById('filter-to').value;

                let totalAmount = 0;
                const categoryTotals = { groceries: 0, transport: 0, bills: 0, fun: 0 };

                for (let i = expenses.length -1; i >= 0; i--) {
                    const exp = expenses[i];
                    let showRow = true;

                    if (filterCategory !== 'all' && exp.category !== filterCategory) {
                        showRow = false;
                    }

                    if (fromDate && exp.date < fromDate) {
                        showRow = false;
                    }

                    if (toDate && exp.date > toDate) {
                        showRow = false;
                    }

                    const row = document.createElement('tr');
                    row.className = 'expense';

                    const amountCell = document.createElement('td');
                    amountCell.textContent = `$${exp.amount.toFixed(2)}`;
                    row.appendChild(amountCell);

                    const categoryCell = document.createElement('td');
                    categoryCell.textContent = exp.category;
                    row.appendChild(categoryCell);

                    const dateCell = document.createElement('td');
                    dateCell.textContent = exp.date;
                    row.appendChild(dateCell);

                    const noteCell = document.createElement('td');
                    noteCell.textContent = exp.note || '';
                    row.appendChild(noteCell);

                    const delBtn = document.createElement('button');
                    delBtn.textContent = 'Del';
                    delBtn.className = 'exp-del';
                    delBtn.onclick = function() {
                        expenses.splice(i, 1);
                        saveExpenses();
                        renderExpenses();
                    };
                    row.appendChild(delBtn);

                    if (!showRow) {
                        row.style.display = 'none';
                    } else {
                        totalAmount += exp.amount;
                        categoryTotals[exp.category] += exp.amount;
                    }

                    tbody.appendChild(row);
                }

                totalEl.textContent = totalAmount.toFixed(2);

                for (const cat of categories) {
                    const el = document.querySelector(`.cat-total[data-cat="${cat}"]`);
                    if (el) {
                        el.textContent = categoryTotals[cat].toFixed(2);
                    }
                }
            }

            renderExpenses();
        });
    </script>
</body>
</html>
